namespace Google\Service\Compute;

class NamedSet extends \Google\Collection
{
  /**
   * The Named Set is a Community Named Set.
   */
  public const TYPE_NAMED_SET_TYPE_COMMUNITY = 'NAMED_SET_TYPE_COMMUNITY';
  /**
   * The Named Set is a Prefix Named Set.
   */
  public const TYPE_NAMED_SET_TYPE_PREFIX = 'NAMED_SET_TYPE_PREFIX';
  protected $collection_key = 'elements';
  /**
   * An optional description of named set.
   *
   * @var string
   */
  public $description;
  protected $elementsType = Expr::class;
  protected $elementsDataType = 'array';
  /**
   * A fingerprint for the Named Set being applied to this Router, which is
   * essentially a hash of the Named Set used for optimistic locking. The
   * fingerprint is initially generated by Compute Engine and changes after
   * every request to modify or update the Named Set. You must always provide an
   * up-to-date fingerprint hash in order to update or change labels.
   *
   * To see the latest fingerprint, make a getNamedSet() request to retrieve a
   * Named Set.
   *
   * @var string
   */
  public $fingerprint;
  /**
   * This set's name, which must be a resource ID segment and unique within all
   * named sets owned by the Router. Name should conform to RFC1035.
   *
   * @var string
   */
  public $name;
  /**
   * This named set's type
   *
   * @var string
   */
  public $type;

  /**
   * An optional description of named set.
   *
   * @param string $description
   */
  public function setDescription($description)
  {
    $this->description = $description;
  }
  /**
   * @return string
   */
  public function getDescription()
  {
    return $this->description;
  }
  /**
   * CEL expressions that are comparable to constructs of this set's type (see
   * Policy Language).
   *
   * @param Expr[] $elements
   */
  public function setElements($elements)
  {
    $this->elements = $elements;
  }
  /**
   * @return Expr[]
   */
  public function getElements()
  {
    return $this->elements;
  }
  /**
   * A fingerprint for the Named Set being applied to this Router, which is
   * essentially a hash of the Named Set used for optimistic locking. The
   * fingerprint is initially generated by Compute Engine and changes after
   * every request to modify or update the Named Set. You must always provide an
   * up-to-date fingerprint hash in order to update or change labels.
   *
   * To see the latest fingerprint, make a getNamedSet() request to retrieve a
   * Named Set.
   *
   * @param string $fingerprint
   */
  public function setFingerprint($fingerprint)
  {
    $this->fingerprint = $fingerprint;
  }
  /**
   * @return string
   */
  public function getFingerprint()
  {
    return $this->fingerprint;
  }
  /**
   * This set's name, which must be a resource ID segment and unique within all
   * named sets owned by the Router. Name should conform to RFC1035.
   *
   * @param string $name
   */
  public function setName($name)
  {
    $this->name = $name;
  }
  /**
   * @return string
   */
  public function getName()
  {
    return $this->name;
  }
  /**
   * This named set's type
   *
   * Accepted values: NAMED_SET_TYPE_COMMUNITY, NAMED_SET_TYPE_PREFIX
   *
   * @param self::TYPE_* $type
   */
  public function setType($type)
  {
    $this->type = $type;
  }
  /**
   * @return self::TYPE_*
   */
  public function getType()
  {
    return $this->type;
  }
}

// Adding a class alias for backwards compatibility with the previous class name.
class_alias(NamedSet::class, 'Google_Service_Compute_NamedSet');
